// OpenCL kernel for streamcluster pgain computation

// Kernel to compute distance costs and update work memory
__kernel void pgain_kernel(
    const Point_Struct* p,
    const float* coord,
    float* work_mem,
    const int* center_table,
    char* switch_membership,
    local float* local_coord,
    int num,
    int dim,
    long x,
    int K
) {
    int i = get_global_id(0);

    if (i >= num) return;

    // Load point x coordinates to local memory
    for (int d = 0; d < dim; d++) {
        local_coord[d] = coord[d * num + x];
    }

    // Calculate distance from point i to point x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - local_coord[d];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        int assign = p[i].assign;
        int center_idx = center_table[assign];
        work_mem[i * (K + 1) + center_idx] += current_cost - x_cost;
    }
}

// Kernel to initialize work memory
__kernel void init_work_mem_kernel(
    float* work_mem,
    int num,
    int K
) {
    int i = get_global_id(0);
    if (i >= num * (K + 1)) return;
    work_mem[i] = 0.0f;
}

// Kernel to initialize switch membership
__kernel void init_switch_kernel(
    char* switch_membership,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;
    switch_membership[i] = 0;
}

// Kernel to copy coordinates to device
__kernel void copy_coord_kernel(
    const float* src,
    float* dest,
    int num,
    int dim
) {
    int idx = get_global_id(0);
    int total = num * dim;
    if (idx >= total) return;
    dest[idx] = src[idx];
}

// Kernel to copy point structures to device
__kernel void copy_point_kernel(
    const Point_Struct* src,
    Point_Struct* dest,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;
    dest[i].weight = src[i].weight;
    dest[i].assign = src[i].assign;
    dest[i].cost = src[i].cost;
}

// Kernel to copy center table to device
__kernel void copy_center_table_kernel(
    const int* src,
    int* dest,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;
    dest[i] = src[i];
}

// Kernel to copy switch membership to device
__kernel void copy_switch_kernel(
    const char* src,
    char* dest,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;
    dest[i] = src[i];
}

// Kernel to copy work memory to host
__kernel void copy_work_mem_kernel(
    const float* src,
    float* dest,
    int total
) {
    int i = get_global_id(0);
    if (i >= total) return;
    dest[i] = src[i];
}
